import { describe, expect, it } from '@a0n/gnosis/test';
import {
  buildSchemaCodemodPlans,
  compileStructuredGraph,
  emitStructuredData,
  extractStructuredDeclarations,
  jsonLdToDeclarations,
  parseProofDeclarationFromValue,
} from './structured-data';

describe('structured-data', () => {
  it('extracts declarations and compiles a deterministic graph', () => {
    const source = `
      <section data-sd-context='{"schema":"https://schema.org/","foaf":"http://xmlns.com/foaf/0.1/"}'>
        <article data-sd-id="#faq" data-sd-type="schema:FAQPage"></article>
        <div data-sd-id="#q1" data-sd-type="schema:Question" data-sd-prop="schema:name" data-sd-value="What is Forkjoin?" />
        <div data-sd-id="#a1" data-sd-type="schema:Answer" data-sd-prop="schema:text" data-sd-value="A graph runtime." />
        <div data-sd-id="#q1" data-sd-prop="schema:acceptedAnswer" data-sd-ref="#a1" />
        <div data-sd-id="#faq" data-sd-prop="schema:mainEntity" data-sd-ref="#q1" />
      </section>
    `;

    const declarations = extractStructuredDeclarations(source, 'faq.tsx');
    expect(declarations.length).toBe(5);

    const first = compileStructuredGraph(declarations, {
      routeId: '/faq',
      baseIri: 'https://example.com/faq',
    });
    const second = compileStructuredGraph(declarations, {
      routeId: '/faq',
      baseIri: 'https://example.com/faq',
    });

    expect(JSON.stringify(first.graph)).toBe(JSON.stringify(second.graph));
    expect(first.graph.tripleCount).toBeGreaterThan(0);
    expect(first.issues).toEqual([]);
  });

  it('emits jsonld/rdfa and best-effort microdata without dropping graph fidelity', () => {
    const declarations = [
      { sdType: 'schema:Thing', sdId: '#thing' },
      { sdId: '#thing', sdProp: 'schema:name', sdValue: 'Thing One' },
      { sdId: '#thing', sdProp: 'foaf:nick', sdValue: 't1' },
    ];

    const compiled = compileStructuredGraph(declarations, {
      routeId: '/thing',
      baseIri: 'https://example.com/thing',
    });

    const emitted = emitStructuredData(compiled.graph, {
      formats: ['jsonld', 'rdfa', 'microdata'],
    });

    expect(emitted.jsonld).toContain('@graph');
    expect(emitted.rdfa).toContain('property="http://xmlns.com/foaf/0.1/nick"');
    expect(emitted.skippedMicrodataTriples).toBeGreaterThanOrEqual(1);
  });

  it('parses proof declarations for lean4 and aeon-logic', () => {
    const lean = parseProofDeclarationFromValue('lean4:buleyean_positivity', {
      status: 'verified',
    });
    const aeonLogic = parseProofDeclarationFromValue(
      'aeon-logic:inference_soundness',
      {
        expression: 'forall x. P(x) -> Q(x)',
      }
    );

    expect(lean?.system).toBe('lean4');
    expect(aeonLogic?.system).toBe('aeon-logic');
    expect(aeonLogic?.expression).toContain('forall');
  });

  it('provides codemod plans for common schema patterns', () => {
    const plans = buildSchemaCodemodPlans();
    expect(plans.length).toBeGreaterThanOrEqual(7);
    expect(plans.some((plan) => plan.pattern === 'FAQPage')).toBe(true);
    expect(plans.some((plan) => plan.pattern === 'Recipe')).toBe(true);
  });

  it('converts manual JSON-LD into declarations for migration', () => {
    const declarations = jsonLdToDeclarations({
      '@context': 'https://schema.org',
      '@type': 'Organization',
      '@id': '#org',
      name: 'Edgework',
      contactPoint: {
        '@type': 'ContactPoint',
        email: 'support@example.com',
      },
    });

    expect(declarations.some((decl) => decl.sdType === 'Organization')).toBe(
      false
    );
    expect(
      declarations.some((decl) => decl.sdType === 'schema:Organization')
    ).toBe(true);
    expect(
      declarations.some((decl) => decl.sdProp === 'schema:contactPoint')
    ).toBe(true);
  });
});
